import {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useId,
  useMemo,
} from 'react';
import { useControllableState } from '../../hooks/useControllableState';

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

export interface RadioGroupContextValue {
  name: string;
  size: 'sm' | 'lg';
  isDisabled: boolean;
  isReadOnly: boolean;
  isLoading: boolean;
  selectedValue: string | null;
  onChildChange: (value: string) => void;
}

export const RadioGroupContext = createContext<RadioGroupContextValue | null>(null);

export function useRadioGroup(): RadioGroupContextValue | null {
  return useContext(RadioGroupContext);
}

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

export interface O9RadioGroupProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange' | 'defaultValue'> {
  name: string;
  label?: string | null;
  orientation?: 'vertical' | 'horizontal';
  labelPosition?: 'top' | 'start';
  size?: 'sm' | 'lg';
  isDisabled?: boolean;
  isReadOnly?: boolean;
  isRequired?: boolean;
  isInvalid?: boolean;
  errorMsg?: string | null;
  isLoading?: boolean;
  value?: string | null;
  defaultValue?: string | null;
  onChange?: (detail: { value: string; previousValue: string | null }) => void;
  children?: React.ReactNode;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9RadioGroup = forwardRef<HTMLDivElement, O9RadioGroupProps>(
  function O9RadioGroup(
    {
      name,
      label = null,
      orientation = 'vertical',
      labelPosition = 'top',
      size = 'lg',
      isDisabled = false,
      isReadOnly: isReadonly = false,
      isRequired = false,
      isInvalid = false,
      errorMsg = null,
      isLoading = false,
      value: valueProp,
      defaultValue = null,
      onChange,
      className,
      children,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const labelId = `o9ds-rb-grp-lbl-${uid}`;
    const errorId = `o9ds-rb-grp-err-${uid}`;

    const [selectedValue, setSelectedValue] = useControllableState(
      valueProp,
      defaultValue,
    );

    const onChildChange = useCallback(
      (childValue: string) => {
        if (isDisabled || isReadonly || isLoading) return;
        setSelectedValue(childValue);
        onChange?.({ value: childValue, previousValue: selectedValue });
      },
      [isDisabled, isReadonly, isLoading, onChange, selectedValue, setSelectedValue]
    );

    const contextValue: RadioGroupContextValue = useMemo(
      () => ({
        name,
        size,
        isDisabled,
        isReadOnly: isReadonly,
        isLoading,
        selectedValue,
        onChildChange,
      }),
      [name, size, isDisabled, isReadonly, isLoading, selectedValue, onChildChange]
    );

    const showAlert = isInvalid && !!errorMsg;

    const classes = [
      'o9ds-rb-grp',
      `o9ds-rb-grp--${size}`,
      orientation === 'horizontal' && 'o9ds-rb-grp--horizontal',
      labelPosition === 'start' && 'o9ds-rb-grp--label-start',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadonly && 'is-readonly',
      isInvalid && 'has-error',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const labelClasses = [
      'o9ds-form-lbl',
      'o9ds-rb-grp__lbl',
      size === 'sm' && 'o9ds-form-lbl--sm',
      isRequired && 'o9ds-form-lbl--required',
      isDisabled && 'is-disabled',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <RadioGroupContext.Provider value={contextValue}>
        <div
          ref={ref}
          className={classes}
          role="radiogroup"
          aria-labelledby={label ? labelId : undefined}
          aria-required={isRequired || undefined}
          aria-invalid={isInvalid || undefined}
          aria-describedby={showAlert ? errorId : undefined}
          aria-busy={isLoading || undefined}
          {...rest}
        >
          {label && (
            <span id={labelId} className={labelClasses}>
              {label}
              {isRequired && (
                <span className="o9ds-form-lbl__req" aria-hidden="true">
                  *
                </span>
              )}
            </span>
          )}
          <div className="o9ds-rb-grp__bdy">
            <div className="o9ds-rb-grp__items">
              {children}
            </div>
            {showAlert && (
              <div
                className="o9ds-inline-alert o9ds-inline-alert--error"
                id={errorId}
                role="alert"
              >
                <span className="o9ds-inline-alert__ico" aria-hidden="true" />
                <span className="o9ds-inline-alert__msg">{errorMsg}</span>
              </div>
            )}
          </div>
        </div>
      </RadioGroupContext.Provider>
    );
  }
);

export default O9RadioGroup;
